// ============================================================
// IML INIT — Establish A0 from burn-in events
// POST body: { action: 'init', agent_id: string, burn_in: [{tool, depth},...] }
// ============================================================
const body = $input.first().json.body;
const agentId = body.agent_id;
const burnIn = body.burn_in || [];

if (!agentId) throw new Error('agent_id required');
if (burnIn.length === 0) throw new Error('burn_in events required');

const ALL_TOOLS = ['safe_read','safe_query','moderate_write','moderate_send','risky_execute','risky_delegate'];

// Compute P0: empirical frequency over burn-in tools
const counts = {};
ALL_TOOLS.forEach(t => counts[t] = 0);
burnIn.forEach(e => {
  const t = e.tool;
  if (counts[t] !== undefined) counts[t]++;
});
const n = burnIn.length;
const P0 = {};
ALL_TOOLS.forEach(t => P0[t] = (counts[t] + 1) / (n + ALL_TOOLS.length));

// Compute depth stats
const depths = burnIn.map(e => e.depth || 1);
const depthMean = depths.reduce((a,b) => a+b, 0) / depths.length;
const depthVar = depths.reduce((a,b) => a + Math.pow(b - depthMean, 2), 0) / depths.length;
const depthStd = Math.sqrt(depthVar) || 1;

// Persist session
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

staticData.sessions[agentId] = {
  P0, depthMean, depthStd,
  step: 0,
  toolCounts: {},
  emaState: 0.0,
  createdAt: Date.now(),
  burnInSize: n
};
ALL_TOOLS.forEach(t => staticData.sessions[agentId].toolCounts[t] = 0);

return [{
  json: {
    status: 'initialized',
    agent_id: agentId,
    burn_in_size: n,
    A0_depth_mean: Math.round(depthMean * 1000) / 1000,
    A0_depth_std: Math.round(depthStd * 1000) / 1000,
    P0
  }
}];

// ============================================================
// IML RESET — Clear session data
// POST body: { action: 'reset', agent_id: string }
// ============================================================
const body = $input.first().json.body;
const agentId = body.agent_id;

const staticData = $getWorkflowStaticData('global');
if (staticData.sessions && staticData.sessions[agentId]) {
  delete staticData.sessions[agentId];
  return [{ json: { status: 'reset', agent_id: agentId } }];
}
return [{ json: { status: 'not_found', agent_id: agentId } }];

// ============================================================
// IML ENGINE — Process event, compute D_hat
// POST body: { agent_id, tool, depth, action? }
// Returns: { step, D_hat, D_t, D_c, D_l, enforcement, alert, alert_level }
// ============================================================

const ALL_TOOLS = ['safe_read','safe_query','moderate_write','moderate_send','risky_execute','risky_delegate'];

const TOOL_RISK = {
  'safe_read': 0.0, 'safe_query': 0.0,
  'moderate_write': 0.5, 'moderate_send': 0.5,
  'risky_execute': 1.0, 'risky_delegate': 1.0
};

// Jensen-Shannon divergence (base-2, returns value in [0,1])
function jsDiv(p, q) {
  let div = 0;
  for (const k of ALL_TOOLS) {
    const pk = p[k] || 1e-10;
    const qk = q[k] || 1e-10;
    const m = (pk + qk) / 2;
    if (pk > 0) div += pk * Math.log2(pk / m);
    if (qk > 0) div += qk * Math.log2(qk / m);
  }
  return Math.min(div / 2, 1.0);
}

const body = $input.first().json.body;
const agentId = body.agent_id;
const tool = body.tool;
const depth = body.depth || 1;

if (!agentId) throw new Error('agent_id required');
if (!tool) throw new Error('tool required');
if (!ALL_TOOLS.includes(tool)) throw new Error('unknown tool: ' + tool);

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

let sess = staticData.sessions[agentId];
if (!sess) {
  // Auto-init with uniform distribution
  const P0 = {};
  ALL_TOOLS.forEach(t => P0[t] = 1 / ALL_TOOLS.length);
  sess = { P0, depthMean: 1.0, depthStd: 1.0, step: 0, toolCounts: {}, emaState: 0.0, createdAt: Date.now(), burnInSize: 0 };
  ALL_TOOLS.forEach(t => sess.toolCounts[t] = 0);
  staticData.sessions[agentId] = sess;
}

// Update trace
sess.step += 1;
sess.toolCounts[tool] = (sess.toolCounts[tool] || 0) + 1;
const step = sess.step;

// P_tau: empirical freq over current trace (Laplace smoothed)
const totalTools = ALL_TOOLS.reduce((s, t) => s + sess.toolCounts[t], 0);
const P_tau = {};
ALL_TOOLS.forEach(t => P_tau[t] = (sess.toolCounts[t] + 1) / (totalTools + ALL_TOOLS.length));

// D_t: temporal drift
const D_t = jsDiv(P_tau, sess.P0);

// D_c: constraint proximity
const D_c = TOOL_RISK[tool] || 0;

// D_l: lineage deviation (capped at 3 sigma)
const depthDev = Math.abs(depth - sess.depthMean) / (sess.depthStd || 1);
const D_l = Math.min(depthDev / 3.0, 1.0);

// D_hat: weighted EMA
const rawD = 0.40 * D_t + 0.35 * D_c + 0.25 * D_l;
sess.emaState = 0.15 * rawD + 0.85 * sess.emaState;
const D_hat = sess.emaState;

// Enforcement: always 0 (T2 theorem)
const enforcement = 0;

// Alert
const alert = D_hat > 0.30;
let alert_level = 'normal';
if (D_hat > 0.50) alert_level = 'high';
else if (D_hat > 0.30) alert_level = 'medium';

// Persist
staticData.sessions[agentId] = sess;

return [{
  json: {
    agent_id: agentId,
    step,
    tool,
    depth,
    D_hat: Math.round(D_hat * 10000) / 10000,
    D_t:   Math.round(D_t   * 10000) / 10000,
    D_c:   Math.round(D_c   * 10000) / 10000,
    D_l:   Math.round(D_l   * 10000) / 10000,
    enforcement,
    alert,
    alert_level,
    timestamp: new Date().toISOString()
  }
}];
